class Solution:
    def solve(self, products: list[tuple]) -> list[str]:
        unique_names = set()
        for name, _ in products:
            unique_names.add(name)
        return sorted(list(unique_names), reverse=True)

if __name__ == '__main__':
    import sys
    products = [line.strip().split(',') for line in sys.stdin.readlines()]
    print(', '.join(map(str, Solution().solve(products))))
